const fs=require('fs');
const input=fs.readFileSync(0,'utf-8').trim().split(/\s+/).map(Number);
let idx=0;
const T=input[idx++];
let res=[];
for(let t=0;t<T;t++){
  const N=input[idx++];
  const cnt=new Array(31).fill(0);
  for(let i=0;i<N;i++){
    const x=input[idx++];
    const msb=31-Math.clz32(x);
    cnt[msb]++;
  }
  let ans=0n;
  for(let k=0;k<31;k++){
    const c=BigInt(cnt[k]);
    ans+=c*(c-1n)/2n;
  }
  res.push(ans.toString());
}
console.log(res.join('\n'));
